float dist(Point p1, Point p2, int dim)
{
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
  return result;
}

static inline float d_dist(int p1, int p2, int num, int dim, float *coord)
{
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord[(i * num) + p1] - coord[(i * num) + p2];
    retval += tmp * tmp;
  }
  return retval;
}

static void kernel_compute_cost_omp(int num, int dim, long x, Point *p, int K, int stride,
                                    float *coord, float *work_mem, int *center_table, bool *switch_membership_arr)
{
#pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem[tid * stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord) * p[tid].weight;
    if (x_cost < p[tid].cost) {
      switch_membership_arr[tid] = 1;
      lower[K] += x_cost - p[tid].cost;
    } else {
      lower[center_table[p[tid].assign]] += p[tid].cost - x_cost;
    }
  }
}

